acceptance_tests.test_meter.py:
import pytest
from meter import cost, RATES

def test_known_model_gpt4():
    assert cost('gpt-4', 1000) == 0.03

def test_known_model_gpt35():
    assert cost('gpt-3.5', 2000) == 0.004

def test_known_model_claude():
    assert cost('claude', 500) == 0.0075

def test_zero_usage():
    assert cost('gpt-4', 0) == 0.0

def test_unknown_model_raises():
    with pytest.raises(ValueError):
        cost('unknown-model', 100)

def test_rates_dict_exists():
    assert 'gpt-4' in RATES and 'gpt-3.5' in RATES and 'claude' in RATES

