files.meter.py:
RATES = {
    'gpt-4': 0.00003,
    'gpt-3.5': 0.000002,
    'claude': 0.000015,
}


def cost(model, usage):
    if model not in RATES:
        raise ValueError(f"Unknown model: {model}")
    return RATES[model] * usage

