from csv_export import to_csv

def test_empty_summary():
    s = {'total_cost': 0.0, 'by_agent': {}, 'count': 0}
    assert to_csv(s) == 'agent,cost\nTOTAL,0.00\n'

def test_single_agent():
    s = {'total_cost': 2.0, 'by_agent': {'A': 2.0}, 'count': 2}
    assert to_csv(s) == 'agent,cost\nA,2.00\nTOTAL,2.00\n'

def test_multi_agent_sorted():
    s = {'total_cost': 6.0, 'by_agent': {'B': 2.0, 'A': 4.0}, 'count': 3}
    assert to_csv(s) == 'agent,cost\nA,4.00\nB,2.00\nTOTAL,6.00\n'

def test_rounding_format():
    s = {'total_cost': 1.005, 'by_agent': {'X': 0.1}, 'count': 1}
    out = to_csv(s)
    assert out.startswith('agent,cost\n')
    assert 'X,0.10' in out
    assert 'TOTAL,1.00' in out or 'TOTAL,1.01' in out

