import pytest
from currency import convert_cost, RATES_TO_USD

def test_usd_to_usd():
    assert convert_cost(10.0, 'USD', 'USD') == 10.0

def test_usd_to_eur():
    assert convert_cost(10.0, 'USD', 'EUR') == round(10.0 / 1.1, 6)

def test_eur_to_usd():
    assert convert_cost(11.0, 'EUR', 'USD') == round(11.0 * 1.1, 6)

def test_gbp_to_eur():
    usd = 5.0 * 1.25
    expected = round(usd / 1.1, 6)
    assert convert_cost(5.0, 'GBP', 'EUR') == expected

def test_unknown_currency_raises():
    with pytest.raises(ValueError):
        convert_cost(10.0, 'XXX', 'USD')
    with pytest.raises(ValueError):
        convert_cost(10.0, 'USD', 'XXX')

def test_negative_amount_raises():
    with pytest.raises(ValueError):
        convert_cost(-5.0, 'USD', 'EUR')

def test_rates_dict_has_required_keys():
    assert 'USD' in RATES_TO_USD and 'EUR' in RATES_TO_USD and 'GBP' in RATES_TO_USD

