RATES_TO_USD = {
    'USD': 1.0,
    'EUR': 1.1,
    'GBP': 1.25,
}


def convert_cost(amount, from_currency, to_currency):
    if amount < 0:
        raise ValueError('amount must be non-negative')
    if from_currency not in RATES_TO_USD:
        raise ValueError(f'unknown currency: {from_currency}')
    if to_currency not in RATES_TO_USD:
        raise ValueError(f'unknown currency: {to_currency}')

    usd = amount * RATES_TO_USD[from_currency]
    result = usd / RATES_TO_USD[to_currency]
