acceptance_tests.test_agent_limits.py:
import pytest
from agent_limits import track_agent_limits

def test_track_agent_limits_ok():
    records = [
        {'agent_id': 'agent_1', 'tokens': 100},
        {'agent_id': 'agent_1', 'tokens': 50}
    ]
    result = track_agent_limits(records, limit_per_day=500)
    assert result['agent_1']['tokens_used'] == 150
    assert result['agent_1']['status'] == 'OK'
    assert result['agent_1']['limit'] == 500

def test_track_agent_limits_warning():
    records = [
        {'agent_id': 'agent_2', 'tokens': 400},
        {'agent_id': 'agent_2', 'tokens': 50}
    ]
    result = track_agent_limits(records, limit_per_day=500)
    assert result['agent_2']['tokens_used'] == 450
    assert result['agent_2']['status'] == 'WARNING'

def test_track_agent_limits_exceeded():
    records = [
        {'agent_id': 'agent_3', 'tokens': 300},
        {'agent_id': 'agent_3', 'tokens': 300}
    ]
    result = track_agent_limits(records, limit_per_day=500)
    assert result['agent_3']['tokens_used'] == 600
    assert result['agent_3']['status'] == 'EXCEEDED'

def test_track_agent_limits_multiple_agents():
    records = [
        {'agent_id': 'agent_1', 'tokens': 100},
        {'agent_id': 'agent_2', 'tokens': 250},
        {'agent_id': 'agent_1', 'tokens': 100}
    ]
    result = track_agent_limits(records, limit_per_day=300)
    assert len(result) == 2
    assert result['agent_1']['tokens_used'] == 200
    assert result['agent_2']['tokens_used'] == 250

