import json
import json_export

def test_simple_dict():
    d = {"total": 12.5, "count": 3}
    s = json_export.to_json(d)
    assert isinstance(s, str)
    assert json.loads(s) == d

def test_nested_dict():
    d = {"agents": {"Dae": 5.0, "Ravi": 3.2}, "labels": ["a","b"], "ok": True}
    s = json_export.to_json(d)
    assert json.loads(s) == d

def test_empty_dict():
    assert json.loads(json_export.to_json({})) == {}

